var countRestrictedPaths = function(n, edges) {
    const MOD = 1000000007n;
    const g = Array.from({length: n + 1}, () => []);
    for (const [u, v, w] of edges) {
        g[u].push([v, w]);
        g[v].push([u, w]);
    }
    const INF = Infinity;
    const dist = new Array(n + 1).fill(INF);
    dist[n] = 0;
    const heap = [[0, n]];
    const up = (i) => { while (i > 0) { const p = (i - 1) >> 1; if (heap[p][0] <= heap[i][0]) break; [heap[p], heap[i]] = [heap[i], heap[p]]; i = p; } };
    const down = (i) => { const m = heap.length; for (;;) { let s = i, l = 2 * i + 1, r = 2 * i + 2; if (l < m && heap[l][0] < heap[s][0]) s = l; if (r < m && heap[r][0] < heap[s][0]) s = r; if (s === i) break; [heap[s], heap[i]] = [heap[i], heap[s]]; i = s; } };
    const push = (x) => { heap.push(x); up(heap.length - 1); };
    const pop = () => { const top = heap[0]; const last = heap.pop(); if (heap.length) { heap[0] = last; down(0); } return top; };
    while (heap.length) {
        const [d, u] = pop();
        if (d > dist[u]) continue;
        for (const [v, w] of g[u]) {
            const nd = d + w;
            if (nd < dist[v]) { dist[v] = nd; push([nd, v]); }
        }
    }
    const order = [];
    for (let i = 1; i <= n; i++) order.push(i);
    order.sort((a, b) => dist[a] - dist[b]);
    const ways = new Array(n + 1).fill(0n);
    ways[n] = 1n;
    for (const u of order) {
        if (u === n) continue;
        let total = 0n;
        for (const [v, w] of g[u]) {
            if (dist[v] < dist[u]) total += ways[v];
        }
        ways[u] = total % MOD;
    }
    return Number(ways[1] % MOD);
};
